// Complete production-ready Task Manager REST API
// Run with: npm init -y && npm i express mongoose bcryptjs jsonwebtoken dotenv cors helmet morgan
// Create .env with: PORT=3000, JWT_SECRET=your-super-secret-key, MONGO_URI=mongodb://localhost:27017/taskmanager
